#[verifier::spinoff_prover]
    pub fn syscall_send_pages(
        &mut self,
        sender_thread_ptr: ThreadPtr,
        sender_endpoint_payload: EndpointIdx,
        sender_va_range: VaRange4K,
    ) -> (ret: SyscallReturnStruct)
        requires
            old(self).wf(),
            old(self).thread_dom().contains(sender_thread_ptr),
            0 <= sender_endpoint_payload < MAX_NUM_ENDPOINT_DESCRIPTORS,
            old(self).get_thread(sender_thread_ptr).state == ThreadState::RUNNING,
            sender_va_range.wf(),
        ensures
            syscall_send_pages_spec(
                *old(self),
                *self,
                sender_thread_ptr,
                sender_endpoint_payload,
                sender_va_range,
                ret,
            ),
    {
        proof {
            self.proc_man.thread_inv();
            self.proc_man.endpoint_inv();
        }

        let sender_container_ptr = self.proc_man.get_thread(sender_thread_ptr).owning_container;
        let sender_proc_ptr = self.proc_man.get_thread(sender_thread_ptr).owning_proc;
        let blocking_endpoint_ptr_op = self.proc_man.get_thread(
            sender_thread_ptr,
        ).endpoint_descriptors.get(sender_endpoint_payload);

        if blocking_endpoint_ptr_op.is_none() {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let blocking_endpoint_ptr = blocking_endpoint_ptr_op.unwrap();
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_send()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
            < MAX_NUM_THREADS_PER_ENDPOINT {
            // Block
            self.proc_man.block_running_thread(
                sender_thread_ptr,
                sender_endpoint_payload,
                IPCPayLoad::Pages { va_range: sender_va_range },
            );
            assert(self.wf());
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_send()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
            >= MAX_NUM_THREADS_PER_ENDPOINT {
            // sender queue is full return error
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_receive()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len() == 0 {
            // change queue state and Block
            self.proc_man.block_running_thread_and_change_queue_state(
                sender_thread_ptr,
                sender_endpoint_payload,
                IPCPayLoad::Pages { va_range: sender_va_range },
                EndpointState::SEND,
            );
            assert(self.wf());
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        assert(self.receiver_exist(sender_thread_ptr, sender_endpoint_payload));

        let receiver_thread_ptr = self.proc_man.get_endpoint(
            blocking_endpoint_ptr,
        ).queue.get_head();
        let receiver_proc_ptr = self.proc_man.get_thread(receiver_thread_ptr).owning_proc;
        let receiver_container_ptr = self.proc_man.get_thread(receiver_thread_ptr).owning_container;
        let receiver_endpoint_payload_op = self.proc_man.get_thread(
            receiver_thread_ptr,
        ).ipc_payload.get_payload_as_va_range();

        if self.proc_man.get_container(receiver_container_ptr).scheduler.len()
            >= MAX_CONTAINER_SCHEDULER_LEN {
            // cannot schedule the receiver
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if receiver_endpoint_payload_op.is_none() {
            // receiver not receiving pages
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let receiver_va_range = receiver_endpoint_payload_op.unwrap();

        if receiver_va_range.len != sender_va_range.len {
            // @Xiangdong TODO schedule the threads and return error
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.check_address_space_va_range_shareable(sender_proc_ptr, &sender_va_range) == false {
            // sender pages not shareable
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.check_address_space_va_range_free(receiver_proc_ptr, &receiver_va_range) == false {
            // receiver addresses are in used
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_container(receiver_container_ptr).quota.mem_4k < receiver_va_range.len
            * 3 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.page_alloc.free_pages_4k.len() < receiver_va_range.len * 3 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if receiver_proc_ptr == sender_proc_ptr {
            // @Xiangdong TODO allow sharing between same procs
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        assert(old(self).get_container(
            old(self).get_thread(
                old(self).get_endpoint(blocking_endpoint_ptr).queue@[0],
            ).owning_container,
        ).scheduler.len() < MAX_CONTAINER_SCHEDULER_LEN);
        self.range_create_and_share_mapping(
            sender_proc_ptr,
            &sender_va_range,
            receiver_proc_ptr,
            &receiver_va_range,
        );
        self.proc_man.schedule_blocked_thread(blocking_endpoint_ptr);
        return SyscallReturnStruct::NoSwitchNew(RetValueType::Else);
    }
